async function rewriteRegistryForStyle(
	registry: Awaited<ReturnType<typeof buildRegistry>>,
	style: PresetConfig["style"],
	styleTempDir: string
): Promise<Awaited<ReturnType<typeof buildRegistry>>> {
	const styleCssPath = path.resolve(INTERNAL_REGISTRY_PATH, "styles", `style-${style}.css`);
	const styleCss = fs.readFileSync(styleCssPath, "utf8");
	const styleMap = parseStyleCss(styleCss);

	const styleItems = await Promise.all(
		registry.map(async (item) => {
			if (!item.files?.length) return item;

			const styleFiles = await Promise.all(
				item.files.map(async (file) => {
					const srcPath = path.resolve(file.path);
					const tempPath = path.join(styleTempDir, file.path);
					const tempDir = path.dirname(tempPath);

					fs.mkdirSync(tempDir, { recursive: true });

					const ext = path.extname(file.path);
					if (TEXT_EXTENSIONS.has(ext)) {
						let content = fs.readFileSync(srcPath, "utf8");
						content = transformContentWithStyle(content, styleMap);
						fs.writeFileSync(tempPath, content, "utf8");
					} else {
						fs.copyFileSync(srcPath, tempPath);
					}

					return { ...file, path: path.relative(process.cwd(), tempPath) };
				})
			);

			return { ...item, files: styleFiles };
		})
	);

	return styleItems;
}

() => {
	if (!demo) return;

	if (agentState !== "speaking" && agentState !== "listening") {
		volumeBands = new Array(barCount).fill(0.2);
		return;
	}

	const startTime = Date.now() / 1000;
	const updateInterval = 50;
	let lastUpdate = 0;

	const updateFakeVolume = (timestamp: number) => {
		if (timestamp - lastUpdate >= updateInterval) {
			const time = Date.now() / 1000 - startTime;
			const newBands = new Array(barCount);

			for (let i = 0; i < barCount; i++) {
				const waveOffset = i * 0.5;
				const baseVolume = Math.sin(time * 2 + waveOffset) * 0.3 + 0.5;
				const randomNoise = Math.random() * 0.2;
				newBands[i] = Math.max(0.1, Math.min(1, baseVolume + randomNoise));
			}

			volumeBands = newBands;
			lastUpdate = timestamp;
		}

		volumeAnimationId = requestAnimationFrame(updateFakeVolume);
	};

	volumeAnimationId = requestAnimationFrame(updateFakeVolume);

	return () => {
		if (volumeAnimationId) {
			cancelAnimationFrame(volumeAnimationId);
		}
	};
}

async upsertDocument(doc: { text: string; uri: string }, isNew: boolean): Promise<void> {
    const filePath = urlToPath(doc.uri) || '';

    if (this.options.tsconfig) {
        const lsContainer = await this.getLSContainer(this.options.tsconfig);
        if (!lsContainer.fileBelongsToProject(filePath, isNew)) {
            return;
        }
    }

    if (
        doc.uri.endsWith('.ts') ||
        doc.uri.endsWith('.js') ||
        doc.uri.endsWith('.tsx') ||
        doc.uri.endsWith('.jsx') ||
        doc.uri.endsWith('.mjs') ||
        doc.uri.endsWith('.cjs') ||
        doc.uri.endsWith('.mts') ||
        doc.uri.endsWith('.cts')
    ) {
        this.pluginHost.updateTsOrJsFile(filePath, [
            {
                range: Range.create(
                    Position.create(0, 0),
                    Position.create(Number.MAX_VALUE, Number.MAX_VALUE)
                ),
                text: doc.text
            }
        ]);
    } else {
        this.docManager.openClientDocument({
            text: doc.text,
            uri: doc.uri
        });
    }
}

function tryParseDate(inputValue: string): Date | null {
  const formatPattern = getDateFormatPattern();
  try {
    const parsedDate = parse(inputValue, formatPattern, new Date());
    if (isValid(parsedDate)) {
      return parsedDate;
    }
  } catch (error) {
    // Continue to next strategy
  }

  const commonFormats = [
    "d.M.yyyy", // German: 17.7.2025
    "dd.MM.yyyy", // German: 17.07.2025
    "M/d/yyyy", // US: 7/17/2025
    "MM/dd/yyyy", // US: 07/17/2025
    "d/M/yyyy", // UK: 17/7/2025
    "dd/MM/yyyy", // UK: 17/07/2025
    "yyyy-MM-dd", // ISO: 2025-07-17
    "yyyy-M-d", // ISO: 2025-7-17
    "M-d-yyyy", // US with dashes: 7-17-2025
    "d-M-yyyy" // EU with dashes: 17-7-2025
  ];

  for (const format of commonFormats) {
    try {
      const parsedDate = parse(inputValue, format, new Date());
      if (isValid(parsedDate)) {
        return parsedDate;
      }
    } catch (error) {
      // Continue to next format
    }
  }

  try {
    const nativeDate = new Date(inputValue);
    if (isValid(nativeDate) && !isNaN(nativeDate.getTime())) {
      return nativeDate;
    }
  } catch (error) {
    // Continue
  }

  return null;
}
